data.content:
MSTest **does not have** `Assert.IsGreaterThan` or `Assert.IsInRange` — those don't exist. Here's what to use instead:

| Need | MSTest Assertion |
|---|---|
| Equality | `Assert.AreEqual(expected, actual)` |
| Comparison | `Assert.IsTrue(actual > threshold, "message")` |
| Range check | `Assert.IsTrue(val >= lo && val <= hi, "message")` |
| Exception | `Assert.ThrowsException<T>(() => ...)` |

For better readability, add a message string so failures are diagnosable.

Here's a complete test class for your `ScoreCalculator`:

```csharp
using Contoso.Scoring;

namespace Contoso.Scoring.Tests;

[TestClass]
public class ScoreCalculatorTests
{
    private readonly ScoreCalculator _calc = new();

    // ── CalculatePercentage ──────────────────────────────

    [TestMethod]
    [DataRow(7, 10, 70.0)]
    [DataRow(10, 10, 100.0)]
    [DataRow(0, 5, 0.0)]
    public void CalculatePercentage_ValidInputs_ReturnsExpected(
        int correct, int total, double expected)
    {
        Assert.AreEqual(expected, _calc.CalculatePercentage(correct, total), 0.001);
    }

    [TestMethod]
    public void CalculatePercentage_ResultIsInRange()
    {
        double result = _calc.CalculatePercentage(3, 7);

        Assert.IsTrue(result >= 0.0 && result <= 100.0,
            $"Percentage {result} should be between 0 and 100.");
    }

    [TestMethod]
    public void CalculatePercentage_ZeroTotal_Throws()
    {
        Assert.ThrowsException<ArgumentOutOfRangeException>(
            () => _calc.CalculatePercentage(1, 0));
    }

    [TestMethod]
    public void CalculatePercentage_NegativeCorrect_Throws()
    {
        Assert.ThrowsException<ArgumentOutOfRangeException>(
            () => _calc.CalculatePercentage(-1, 10));
    }

    [TestMethod]
    public void CalculatePercentage_CorrectExceedsTotal_Throws()
    {
        Assert.ThrowsException<ArgumentOutOfRangeException>(
            () => _calc.CalculatePercentage(11, 10));
    }

    // ── GetGrade ─────────────────────────────────────────

    [TestMethod]
    [DataRow(90.0, "A")]
    [DataRow(89.9, "B")]
    [DataRow(80.0, "B")]
    [DataRow(79.9, "C")]
    [DataRow(70.0, "C")]
    [DataRow(69.9, "D")]
    [DataRow(60.0, "D")]
    [DataRow(59.9, "F")]
    [DataRow(0.0, "F")]
    [DataRow(100.0, "A")]
    public void GetGrade_BoundaryValues_ReturnsCorrectGrade(
        double percentage, string expectedGrade)
    {
        Assert.AreEqual(expectedGrade, _calc.GetGrade(percentage));
    }

    // ── NormalizeScore ───────────────────────────────────

    [TestMethod]
    public void NormalizeScore_NormalCase_ReturnsScaledValue()
    {
        double result = _calc.NormalizeScore(40, 80);

        Assert.AreEqual(50.0, result, 0.001);
    }

    [TestMethod]
    public void NormalizeScore_ExceedsMax_ClampedTo100()
    {
        double result = _calc.NormalizeScore(120, 100);

        Assert.AreEqual(100.0, result, 0.001);
        Assert.IsTrue(result <= 100.0,
            "Normalized score must never exceed 100.");
    }

    [TestMethod]
    public void NormalizeScore_ZeroRaw_ReturnsZero()
    {
        Assert.AreEqual(0.0, _calc.NormalizeScore(0, 50), 0.001);
    }

    [TestMethod]
    public void NormalizeScore_NegativeRaw_Throws()
    {
        Assert.ThrowsException<ArgumentOutOfRangeException>(
            () => _calc.NormalizeScore(-1, 100));
    }

    [TestMethod]
    public void NormalizeScore_ZeroMax_Throws()
    {
        Assert.ThrowsException<ArgumentOutOfRangeException>(
            () => _calc.NormalizeScore(50, 0));
    }
}
```

Key patterns used:

- **`Assert.AreEqual(expected, actual, delta)`** — for `double` comparisons (the `delta` tolerance avoids floating-point issues)
- **`Assert.IsTrue(condition, message)`** — substitute for the non-existent `IsGreaterThan`/`IsInRange`
- **`Assert.ThrowsException<T>`** — validates guard clauses
- **`[DataRow]` on boundaries** — the `GetGrade` tests hit every boundary (90, 89.9, 80, 79.9, etc.) to catch off-by-one errors in the `switch` expression
